refentry.refsect1:
&reftitle.returnvalues;

 При передаче в параметр key строки функция возвращает &true;, если завершилась успешно, или &false;, если возникла ошибка.



 При передаче в параметр key массива функция возвращает:



    Пустой массив, если все пары «имя => значение» в массиве возможно установить;




    Значение &false;, если в массиве невозможно установить все пары «имя => значение»;




    Массив пар «имя => значение», которые не добавились в пользовательский кеш,
    если одни пары возможно установить, а другие — нет.

  &reftitle.examples;




     Пример добавления переменной в пользовательский кеш функцией wincache_ucache_add
     со строковым ключом key



<?php

$bar = 'BAR';
var_dump(wincache_ucache_add('foo', $bar));
var_dump(wincache_ucache_add('foo', $bar));
var_dump(wincache_ucache_get('foo'));


    &example.outputs;


bool(true)
bool(false)
string(3) "BAR"








     Пример добавления переменных в пользовательский кеш функцией wincache_ucache_add
     с передачей в параметр key массива



<?php

$colors_array = array('green' => '5', 'Blue' => '6', 'yellow' => '7', 'cyan' => '8');

var_dump(wincache_ucache_add($colors_array));
var_dump(wincache_ucache_add($colors_array));
var_dump(wincache_ucache_get('Blue'));


    &example.outputs;


array(0) { }
array(4) {
  ["green"]=> int(-1)
  ["Blue"]=> int(-1)
  ["yellow"]=> int(-1)
  ["cyan"]=> int(-1)
}
string(1) "6"
